INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "お！\nあそこに困ってそうな人発見！", "ねぇねぇ、騎士クン\n手伝ってあげようよ～", "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 0, "春咲 ひより", 0, 2, 1, 0, 0, 1.4, 1, 1, 1001);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "大切な人を\n守れるようになりたい…って", "わ、わたし、\nなに言ってるんだろ\nあはは…", "みんなみたいに\nわたしも強くならなきゃ", 0, "草野 優衣", 0, 2, 1, 0, 0, 1.4, 1, 1, 1002);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "キミに必要な集中力と感性が", "少しは磨かれると思いますよ。", "フェンシングを始めてみては？", 0, "士条 怜", 0, 2, 1, 0, 0, 1.4, 1, 1, 1003);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "今日はなにして遊ぶ？", "みそぎはねぇ、\nかくれんぼやりたい！", "ねぇ、にいちゃん！", 0, "穂高 みそぎ", 0, 2, 1, 0, 0, 1.5, 1, 1, 1004);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ねぇ…", "私といっしょに…\nいかない？", "風宮あかりです", 0, "風宮 あかり", 0, 2, 1, 0, 0, 1.4, 1, 1, 1006);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "プリンたべたいのー", "食べ物の恨みは怖いのー", "出雲宮子なのー", 0, "出雲 宮子", 0, 2, 1, 0, 0, 1.5, 1, 1, 1007);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "キミもボクの美貌に\n吸い寄せられたんだね。", "いいよ。\n見られることは運命さ…", "ボクは虹村雪。", 0, "虹村 雪", 0, 2, 1, 0, 0, 1.4, 1, 1, 1008);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", "人呼んで「疾風の冥姫」!!", "フッ…聞いて後悔するがいい！", 0, "柊杏奈", 0, 2, 1, 0, 0, 1.4, 1, 1, 1009);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", "ほんまおおきにやわ～♪", "マホマホ王国のプリンセス、\nまほ姫どす", 0, "姫宮 真歩", 0, 2, 1, 0, 0, 1.5, 1, 1, 1010);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "生き別れたお兄ちゃんを探して\n三千世界！", "ここで会ったが\n100年目～！", "衣之咲璃乃です！", 0, "衣之咲 璃乃", 0, 2, 1, 0, 0, 1.4, 1, 1, 1011);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ち、超能力って…\n何のことかな～？", "…って、お願い！\n誰にも言わないでおいて～！", "私はハツネ、\n結構強いんだよ。\nきらーん☆", 0, "柏崎 初音", 0, 2, 1, 0, 0, 1.4, 1, 1, 1012);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "一応カリスマ読モJKやってまっす！", "ヒデサイまぢ\nGF（グッドフィーリング）～♪", "ちょす！\n美波鈴奈だよ～♪", 0, "美波 鈴奈", 0, 2, 1, 0, 0, 1.4, 1, 1, 1016);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "東京は遊園地みたいなところさー", "でも、沖縄もとってもいいとこさー", "はいたーい。\n喜屋武香織さー。", 0, "喜屋武 香織", 0, 2, 1, 0, 0, 1.4, 1, 1, 1017);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "先生って呼ばれるのは\nくすぐったいから", "イオちゃんって呼んでね。", "支倉伊緒です。", 0, "支倉 伊緒", 0, 2, 1, 0, 0, 1.4, 1, 1, 1018);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "あ！/\お兄ちゃ～ん\nまってよ～", "ミミをおいてかないでぇ～", "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 0, "茜 ミミ", 0, 2, 1, 0, 0, 1.5, 1, 1, 1020);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "あの……\nふぇ……", "ふぇぇぇぇぇん……", "あ…あの…えっと…\n栗…林…くるみ…です……", 0, "栗林 くるみ", 0, 2, 1, 0, 0, 1.5, 1, 1, 1021);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "こんな私に貴重な時間を\n割いていただき、", "なんてありがとうございます！", "風宮よりです。\nあああああ！", 0, "風宮 より", 0, 2, 1, 0, 0, 1.4, 1, 1, 1022);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "おにいちゃんどこいくの？\nえ？", "私こっち行きたいー\nね、早く早くー", "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 0, "北条 綾音", 0, 2, 1, 0, 0, 1.5, 1, 1, 1023);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ふ、不束者ですが\nどうぞ末永く…って、", "これて何か違う…\nあああすみません！", "わっ…わっ…私、\n天野すずめといいます！", 0, "天野 すずめ", 0, 2, 1, 0, 0, 1.4, 1, 1, 1025);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "あなたは…運命の……\n伴侶……", "離しませんわ………\n絶対に…!!", "……クスクス…私は\n…倉石恵理子……", 0, "倉石 恵理子", 0, 2, 1, 0, 0, 1.4, 1, 1, 1027);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", "…そうでしょ？？", "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 0, "佐々木 咲恋", 0, 2, 1, 0, 0, 1.4, 1, 1, 1028);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ぇっと…\nキミ、私のこと知らないの?!", "あはは、\n私もまだまだだなぁ～", "桜井望だよ！\nよろしくねっ", 0, "桜井 望", 0, 2, 1, 0, 0, 1.4, 1, 1, 1029);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "初めまして、\n私はニノン・ジュベール申すデス！", "ショーグン、\nワタシと一緒に天下統一デース！", "デケデケデンっ！", 0, "ニノン・ジュベール", 0, 2, 1, 0, 0, 1.4, 1, 1, 1030);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "でもって私の隣にいるのが……\nえ、見えない？", "おかしいですね……", "上喜しのぶです。\n手元のドクロが父です。", 0, "上喜 しのぶ", 0, 2, 1, 0, 0, 1.4, 1, 1, 1031);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "けんども\nそれには足りないモンが…", "そう、\nオラのボケに突っ込める相方が…！", "目指すはビッグな\nお笑い芸人だっぺ！", 0, "野戸まひる", 0, 2, 1, 0, 0, 1.5, 1, 1, 1033);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ちょっと緊張しちゃって…", "ちょ\nちょっと一杯飲んできます…！", "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 0, "綾瀬 ゆかり", 0, 2, 1, 0, 0, 1.4, 1, 1, 1034);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "知らない人とは話しちゃいけないので", "これ以上お話しすることは…\nないです！", "氷川鏡華…です", 0, "氷川 鏡華", 0, 2, 1, 0, 0, 1.5, 1, 1, 1036);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "……あ、アラーム。", "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", "柏崎…栞です。", 0, "柏崎 栞", 0, 2, 1, 0, 0, 1.4, 1, 1, 1038);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "私、一人も友達がいなくて……", "野に咲く花が、\n唯一の話相手です。", "ふ、双葉碧です。", 0, "双葉 碧", 0, 2, 1, 0, 0, 1.4, 1, 1, 1040);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", "そう思っています。", "三角千歌です。", 0, "三角 千歌", 0, 2, 1, 0, 0, 1.4, 1, 1, 1042);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "あぁ？\nお前のそいつの仲間か？", "う、疑ってすまなかったな…", "安芸真琴だ。", 0, "安芸 真琴", 0, 2, 1, 0, 0, 1.4, 1, 1, 1043);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "生けとし生ける全ての者よ！", "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", "わらわこそは夜を総べる者！", 0, "イリヤ・オーンスタイン", 0, 2, 1, 0, 0, 1.4, 1, 1, 1044);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "ぐふふふふ……はっ！", "ｌク、クウカに何かご用ですか!?", "そこで騎士は妖精を乱暴に……", 0, "遠見 空花", 0, 2, 1, 0, 0, 1.4, 1, 1, 1045);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "自由気ままで♪\n寝て遊んで、食べてケンカして…", "う～ん…\n猫ってホントに最高にゃ～♪", "宮坂たまきにゃ♪\n猫はいいにゃよ？", 0, "宮坂たまき", 0, 2, 1, 0, 0, 1.4, 1, 1, 1046);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "それでは早速クエストに…", "…と思ったら\nバイトの時間だ！\nまたあとでね！", "大神美冬よ！", 0, "大神 美冬", 0, 2, 1, 0, 0, 1.4, 1, 1, 1048);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "クエストもバトルも\n掃除も洗濯も", "お姉ちゃんがぜ～んぶ\nやってあげるからね！", "星野静流だよ！", 0, "星野静流", 0, 2, 1, 0, 0, 1.4, 1, 1, 1049);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "見ての通りの\nセクシー美少女で", "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", "アタシは玉泉美咲。", 0, "玉泉美咲", 0, 2, 1, 0, 0, 1.5, 1, 1, 1050);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "？？？？", "？？？？", "？？？", 0, "リマ", 0, 2, 1, 0, 0, 1.4, 1, 1, 1052);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 0, "モニカ・ヴァイスヴィント", 0, 2, 1, 0, 0, 1.5, 1, 1, 1053);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 0, "ペコリーヌ", 0, 2, 1, 0, 0, 1.5, 1, 1, 1058);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 0, "コッコロ", 0, 2, 1, 0, 0, 1.5, 1, 1, 1059);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (0, "菓子でつろうなどと\n稚拙な策を……", "そ、そこまでいうなら\nもらってやる", "モニカ・ヴァイスヴィントだ。", 0, "キャル", 0, 2, 1, 0, 0, 1.5, 1, 1, 1060);
